import { queryOptions, type UseQueryOptions } from "@tanstack/react-query";
import { getApiClient } from "../apiClientInstance";
import type { ApiClientError, ApiNamespace } from "../types/client";
import type { GeneratedQueryKey } from "../types/query";
import type { Params } from "../utils/cleanParams";
import { makeSearchParams } from "../utils/makeSearchParams";

export type UseGetOneOptions<TQueryFnData> = Omit<
  UseQueryOptions<
    TQueryFnData,
    ApiClientError,
    TQueryFnData,
    GeneratedQueryKey
  >,
  "queryFn" | "queryKey"
> & {
  namespace?: ApiNamespace;
  performRedirect?: boolean;
  resourceKey?: string;
};

export const useGetOneQueryOptions = <DataShape>(
  path: string,
  params: Params,
  queryKey: GeneratedQueryKey,
  options: Partial<UseGetOneOptions<DataShape>> = {},
) => {
  const { namespace = "org", performRedirect, ...useQueryOptions } = options;

  const queryParams = makeSearchParams(params);

  const hydratedPath = `${path}?${queryParams.toString()}`;

  return queryOptions({
    queryFn: () =>
      getApiClient(performRedirect, namespace).get<DataShape>(
        hydratedPath,
        undefined,
      ),
    queryKey,
    ...useQueryOptions,
  });
};

